import{_ as o,o as e,c as a,a4 as d}from"./chunks/framework.CDpUjPX_.js";const u=JSON.parse('{"title":"Motores & Metricas","description":"","frontmatter":{},"headers":[],"relativePath":"admin/motors-metrics.md","filePath":"admin/motors-metrics.md"}'),r={name:"admin/motors-metrics.md"};function i(s,t,n,c,l,m){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="motores-metricas" tabindex="-1">Motores &amp; Metricas <a class="header-anchor" href="#motores-metricas" aria-label="Permalink to &quot;Motores &amp; Metricas&quot;">​</a></h1><p>Paginas de monitoramento, saude e metricas dos motores de busca do Kubex. Permite ao admin acompanhar status, disparar execucoes manuais e visualizar KPIs de performance.</p><hr><h2 id="monitoring-—-status-e-triggers" tabindex="-1">Monitoring — Status e Triggers <a class="header-anchor" href="#monitoring-—-status-e-triggers" aria-label="Permalink to &quot;Monitoring — Status e Triggers&quot;">​</a></h2><p><strong>Admin pages:</strong> <code>/monitoring</code>, <code>/motors</code>, <code>/health</code><strong>Arquivo:</strong> <code>app/api/v1/admin/monitoring_admin.py</code> (11KB) <strong>Rate limit:</strong> 30 req/min nos triggers</p><h3 id="endpoints-8" tabindex="-1">Endpoints (8) <a class="header-anchor" href="#endpoints-8" aria-label="Permalink to &quot;Endpoints (8)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/monitoring/status</code></td><td>Status geral de todos os motores (last run, next run, is_active)</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/start</code></td><td>Iniciar monitoramento global</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/stop</code></td><td>Parar monitoramento global</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/trigger-image-rescan</code></td><td>Trigger manual Lens</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/trigger-crawler</code></td><td>Trigger manual Crawler</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/trigger-name-monitoring</code></td><td>Trigger manual BrandWatch</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/trigger-telegram</code></td><td>Trigger manual Telegram Monitor</td></tr><tr><td><code>POST</code></td><td><code>/admin/monitoring/trigger-social/{motor}</code></td><td>Trigger manual motores sociais</td></tr></tbody></table><h4 id="motores-sociais-disponiveis" tabindex="-1">Motores sociais disponiveis <a class="header-anchor" href="#motores-sociais-disponiveis" aria-label="Permalink to &quot;Motores sociais disponiveis&quot;">​</a></h4><p>O endpoint <code>trigger-social/{motor}</code> aceita os seguintes valores no path parameter:</p><ul><li><code>discord</code></li><li><code>reddit</code></li><li><code>google_alerts</code></li><li><code>twitter</code></li><li><code>darkweb</code></li><li><code>instagram</code></li><li><code>facebook</code></li><li><code>flickr</code></li></ul><hr><h2 id="motor-health" tabindex="-1">Motor Health <a class="header-anchor" href="#motor-health" aria-label="Permalink to &quot;Motor Health&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/motors</code></p><p>Mostra status de saude de cada motor individualmente:</p><ul><li><strong>Ultimo run</strong> — timestamp da ultima execucao</li><li><strong>Resultado</strong> — sucesso ou falha</li><li><strong>Circuit breaker status</strong> — aberto, fechado ou half-open</li><li><strong>Erros recentes</strong> — lista dos ultimos erros registrados</li></ul><hr><h2 id="system-health" tabindex="-1">System Health <a class="header-anchor" href="#system-health" aria-label="Permalink to &quot;System Health&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/health</code><strong>Arquivo:</strong> <code>app/api/v1/admin/system.py</code><strong>Endpoint:</strong> <code>GET /admin/system/health</code></p><p>Retorna <code>SystemHealth</code> com as seguintes informacoes:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Descricao</th></tr></thead><tbody><tr><td>Circuit breakers</td><td>Status de todos os servicos (aberto/fechado/half-open)</td></tr><tr><td>Dead Letter Queue</td><td>Tarefas falhadas pendentes de reprocessamento</td></tr><tr><td>Latencia DB</td><td>Tempo de resposta do PostgreSQL</td></tr><tr><td>Latencia Redis</td><td>Tempo de resposta do Redis</td></tr><tr><td>Proxy pool</td><td>Status e disponibilidade dos proxies</td></tr><tr><td>Storage</td><td>Status do armazenamento</td></tr><tr><td>Motor timestamps</td><td>Timestamp do ultimo run de cada motor</td></tr></tbody></table><hr><h2 id="metricas" tabindex="-1">Metricas <a class="header-anchor" href="#metricas" aria-label="Permalink to &quot;Metricas&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/metricas</code><strong>Arquivo:</strong> <code>app/api/v1/admin/metrics_admin.py</code></p><h3 id="endpoints-3" tabindex="-1">Endpoints (3) <a class="header-anchor" href="#endpoints-3" aria-label="Permalink to &quot;Endpoints (3)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/metrics/overview</code></td><td>KPIs gerais: total de usuarios, buscas, alertas, receita</td></tr><tr><td><code>GET</code></td><td><code>/admin/metrics/motors</code></td><td>Performance por motor: execucoes, sucessos, falhas, latencia media</td></tr><tr><td><code>GET</code></td><td><code>/admin/metrics/motors/health</code></td><td>Health check de cada motor (ultimo run, status)</td></tr></tbody></table><h3 id="kpis-do-overview" tabindex="-1">KPIs do Overview <a class="header-anchor" href="#kpis-do-overview" aria-label="Permalink to &quot;KPIs do Overview&quot;">​</a></h3><ul><li><strong>Total de usuarios</strong> — cadastrados na plataforma</li><li><strong>Buscas realizadas</strong> — quantidade total de buscas executadas</li><li><strong>Alertas gerados</strong> — total de alertas de violacao</li><li><strong>Receita</strong> — valor total acumulado</li></ul><h3 id="performance-por-motor" tabindex="-1">Performance por Motor <a class="header-anchor" href="#performance-por-motor" aria-label="Permalink to &quot;Performance por Motor&quot;">​</a></h3><p>O endpoint <code>/admin/metrics/motors</code> retorna para cada motor:</p><ul><li>Numero de execucoes</li><li>Taxa de sucesso e falha</li><li>Latencia media por execucao</li></ul><hr><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/dashboard</code><strong>Arquivo:</strong> <code>app/api/v1/admin/dashboard.py</code><strong>Endpoint:</strong> <code>GET /admin/dashboard</code></p><p>KPIs consolidados exibidos no dashboard principal:</p><table tabindex="0"><thead><tr><th>KPI</th><th>Descricao</th></tr></thead><tbody><tr><td>Usuarios ativos</td><td>Usuarios com sessao ativa no periodo</td></tr><tr><td>Buscas do dia</td><td>Total de buscas executadas hoje</td></tr><tr><td>Receita mensal</td><td>Faturamento acumulado no mes corrente</td></tr><tr><td>Saude dos motores</td><td>Status resumido de cada motor</td></tr><tr><td>Alertas recentes</td><td>Ultimos alertas de violacao detectados</td></tr></tbody></table>',35)])])}const g=o(r,[["render",i]]);export{u as __pageData,g as default};
